  ('social-worker-moex-04702', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某低收入戶獨居老人住家屋頂漏水，申請住屋修繕補助，政府採簡化申請核銷撥付款行政程序， 並提供修繕服務，只要符合福利身分，透過單一窗口式服務（One-StopService）完成申請，這種 強調申請使用程序上的方便，係屬於下列那種服務品質要素？', '["可獲性（availability）", "可近性（accessibility）", "可接受性（acceptability）", "可負擔性（affordability）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:27+00:00", "source_pdf_sha1": "d2478f6e5f47", "answer_pdf_sha1": "eead980aaadb", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
